const UserDetails = JSON.parse(localStorage.getItem("UserDetails"));
const groups = UserDetails ? UserDetails["groups"] : [];
const isReviewer = groups.includes("/formsflow/formsflow-reviewer");
const status = data.applicationStatus;
if ((isReviewer && (status === "New" || status === "Resubmitted")) || status === "Resubmit" || status === "Approved" || status === "Rejected") {
  show = true;
}
else {
  show = false;
};

const status = data.applicationStatus;
if (status === 'Resubmit' || status === 'Approved' || status === 'Rejected') {
  show = false;
} else {
  show = true;
  if(data.personalInformation && data.personalInformation.action){
    component.disabled=false;
  }else{
    component.disabled=true;
  }
}

components.custom:
form.formio.saveSubmission(form.submission).then(result => {
  console.log('Submission saved:', result);
  form.emit('customEvent', {
    type: "actionComplete",
    component: component,
    actionType: form.submission.data.personalInformation.action
  });
}).catch(error => {
  console.error('Error saving submission:', error);
});

components.customConditional:
switch(data.applicationStatus) {
  case "New":
  case "Resubmitted":
  case "Approved":
  case "Rejected":
    show = false;
    break;
  default: show = true;
};
